const combined = items.map(item => {
  const data = item.json.data;

  if (typeof data === 'string') return data;
  if (Array.isArray(data)) return data.join(' ');
  if (typeof data === 'object') return JSON.stringify(data);
  return String(data);
}).join('\n\n---\n\n');

return [{
  json: {
    combinedData: combined
  }
}];
